598	/// Moves `nres` results from their current position on the stack to `res_idx`,
599	/// padding with `Nil` if fewer than `wanted` results are present, or discarding
600	/// extras if more are present.
601	///
602	/// C: `l_sinline void moveresults(lua_State *L, StkId res, int nres, int wanted)`
603	#[inline]
604	fn move_results(
605	    state: &mut LuaState,
606	    res_idx: StackIdx,
607	    nres: i32,
608	    wanted: i32,
609	) -> Result<(), LuaError> {
610	    // C: switch (wanted) — handle common cases separately
611	    match wanted {
612	        0 => {
613	            // C: L->top.p = res; return;
614	            state.set_top(res_idx);
615	            return Ok(());
616	        }
617	        1 => {
618	            if nres == 0 {
619	                // C: setnilvalue(s2v(res))
620	                state.set_at(res_idx, LuaValue::Nil);
621	            } else {
622	                // C: setobjs2s(L, res, L->top.p - nres)
623	                let top = state.top_idx();
624	                let src = state.get_at(top - nres as i32).clone();
625	                state.set_at(res_idx, src);
626	            }
627	            // C: L->top.p = res + 1
628	            state.set_top(res_idx + 1);
629	            return Ok(());
630	        }
631	        LUA_MULTRET => {
632	            // wanted = nres: fall through to generic case below
633	        }
634	        _ => {
635	            // C: if (hastocloseCfunc(wanted))
636	            // hastocloseCfunc → n < LUA_MULTRET  (macros.tsv)
637	            if wanted < LUA_MULTRET {
638	                let ci_idx = state.ci;
639	                // C: L->ci->callstatus |= CIST_CLSRET; L->ci->u2.nres = nres;
640	                state.get_ci_mut(ci_idx).callstatus |= CIST_CLSRET;
641	                state.set_ci_u2_nres(ci_idx, nres);
642	
643	                // C: res = luaF_close(L, res, CLOSEKTOP, 1)
644	                // TODO(port): CLOSE_K_TOP sentinel needs proper StackIdx encoding
645	                // in func::close; for now pass as a special sentinel value.
646	                let res_idx = func::close(state, res_idx, CLOSE_K_TOP, true)?;
647	
648	                let ci_idx = state.ci;
649	                // C: L->ci->callstatus &= ~CIST_CLSRET
650	                state.get_ci_mut(ci_idx).callstatus &= !CIST_CLSRET;
651	
652	                if state.hookmask != 0 {
653	                    // C: ptrdiff_t savedres = savestack(L, res)
654	                    // savestack → idx  (macros.tsv: StackIdx is already stable)
655	                    let saved_res = res_idx;
656	                    rethook(state, ci_idx, nres)?;
657	                    // C: res = restorestack(L, savedres) — already stable
658	                    let _ = saved_res; // = res_idx (no-op restore)
659	                }
660	
661	                // C: wanted = decodeNresults(wanted)
662	                // decodeNresults → -(n) - 3  (macros.tsv)
663	                let decoded_wanted = -(wanted) - 3;
664	                let wanted = if decoded_wanted == LUA_MULTRET {
665	                    nres
666	                } else {
667	                    decoded_wanted
668	                };
669	
670	                // Fall into generic case with updated wanted.
671	                let first_result = state.top_idx().0 as i32 - nres;
672	                let actual_nres = nres.min(wanted);
673	                for i in 0..actual_nres {
674	                    let src = state.get_at((first_result + i) as u32).clone();
675	                    state.set_at(res_idx + i as i32, src);
676	                }
677	                for i in actual_nres..wanted {
678	                    state.set_at(res_idx + i as i32, LuaValue::Nil);
679	                }
680	                state.set_top(res_idx + wanted as i32);
681	                return Ok(());
682	            }
683	        }
684	    }
685	
686	    // Generic case (also reached from LUA_MULTRET with wanted = nres).
687	    let effective_wanted = if wanted == LUA_MULTRET { nres } else { wanted };
688	    let first_result = state.top_idx().0 as i32 - nres;
689	    let actual_nres = nres.min(effective_wanted);
690	    for i in 0..actual_nres {
691	        let src = state.get_at((first_result + i) as u32).clone();
692	        state.set_at(res_idx + i as i32, src);
693	    }
694	    for i in actual_nres..effective_wanted {
695	        state.set_at(res_idx + i as i32, LuaValue::Nil);
696	    }
697	    state.set_top(res_idx + effective_wanted as i32);
698	    Ok(())
699	}
