701	/// Finishes a function call: calls hook if needed, moves results into place,
702	/// and pops the current call frame.
703	///
704	/// C: `void luaD_poscall(lua_State *L, CallInfo *ci, int nres)`
705	pub(crate) fn poscall(
706	    state: &mut LuaState,
707	    ci_idx: CallInfoIdx,
708	    nres: i32,
709	) -> Result<(), LuaError> {
710	    // C: int wanted = ci->nresults;
711	    let wanted = state.get_ci(ci_idx).nresults as i32;
712	
713	    // C: if (l_unlikely(L->hookmask && !hastocloseCfunc(wanted))) rethook(L, ci, nres);
714	    if state.hookmask != 0 && !(wanted < LUA_MULTRET) {
715	        rethook(state, ci_idx, nres)?;
716	    }
717	
718	    // C: moveresults(L, ci->func.p, nres, wanted)
719	    let func_idx = state.get_ci(ci_idx).func;
720	    move_results(state, func_idx, nres, wanted)?;
721	
722	    // C: lua_assert(!(ci->callstatus & (CIST_HOOKED|CIST_YPCALL|CIST_FIN|CIST_TRAN|CIST_CLSRET)))
723	    debug_assert!(
724	        state.get_ci(ci_idx).callstatus
725	            & (CIST_HOOKED | CIST_YPCALL | CIST_FIN | CIST_TRAN | CIST_CLSRET)
726	            == 0
727	    );
728	
729	    // C: L->ci = ci->previous
730	    let previous = state
731	        .get_ci(ci_idx)
732	        .previous
733	        .expect("poscall: no previous call frame");
734	    state.ci = previous;
735	    Ok(())
736	}
