/// C: static void forstat(LexState *ls, int line)
fn forstat(ls: &mut LexState, state: &mut LuaState, line: i32) -> Result<(), LuaError> {
    enter_block(ls, true); // scope for loop and control variables
    // C: luaX_next(ls) — skip 'for'
