    /// C: vd.pidx — index in Proto.locvars
    pub pidx: i16,
    /// C: vd.name — variable name
    pub name: Option<GcRef<LuaString>>,
    /// C: k — compile-time constant value (only valid for CompileTimeConst)
    pub const_val: LuaValue,
}

impl Default for VarDesc {
    fn default() -> Self {
        VarDesc {
            kind: VarKind::Reg,
            ridx: 0,
