/// C: static void retstat(LexState *ls)
fn retstat(ls: &mut LexState, state: &mut LuaState) -> Result<(), LuaError> {
    let mut first = {
        let fs = ls.fs.as_ref().unwrap();
        nvarstack(ls, fs)
    };
    let mut nret: i32;
    if block_follow(ls, true) || ls.t.token == b';' as TokenKind {
        nret = 0;
    } else {
        let mut e = ExprDesc::default();
        nret = explist(ls, state, &mut e)?;
        if e.k.has_mult_ret() {
            // C: luaK_setmultret(fs, &e)
            cg_set_returns(ls.fs.as_mut().unwrap(), &mut e, LUA_MULTRET);
            if e.k == ExprKind::Call && nret == 1 {
                // C: tail call check — !fs->bl->insidetbc
                let insidetbc = ls.fs.as_ref().unwrap().bl.as_ref().map_or(false, |b| b.insidetbc);
                if !insidetbc {
                    // C: SET_OPCODE(getinstruction(fs, &e), OP_TAILCALL)
                    let fs = ls.fs.as_mut().unwrap();
                    let info = e.u.info as usize;
                    let mut lc = lua_code::opcodes::Instruction(fs.f.code[info].0);
                    lc.set_opcode(lua_code::opcodes::OpCode::TailCall);
                    fs.f.code[info] = lua_types::opcode::Instruction::new(lc.0);
                }
            }
            nret = LUA_MULTRET;
        } else {
            let line = ls.linenumber;
            if nret == 1 {
                // C: first = luaK_exp2anyreg(fs, &e)
                first = cg_exp_to_any_reg(ls.fs.as_mut().unwrap(), line, &mut e)? as i32;
            } else {
                // C: values must go to the top of the stack
                cg_exp_to_next_reg(ls.fs.as_mut().unwrap(), line, &mut e)?;
            }
        }
    }
    // C: luaK_ret(fs, first, nret)
    let line = ls.linenumber;
    cg_emit_return(ls.fs.as_mut().unwrap(), line, first, nret);
    // C: testnext(ls, ';')
    test_next(ls, state, b';' as TokenKind)?;
    Ok(())
}

/// C: static void statement(LexState *ls)
/// Top-level statement dispatcher.
fn statement(ls: &mut LexState, state: &mut LuaState) -> Result<(), LuaError> {
    let line = ls.linenumber;
    // C: enterlevel(ls)
    // TODO(port): state.inc_c_calls()?;
    match ls.t.token {
        c if c == b';' as TokenKind => {
            lex_next(ls, state)?;
        }
        TK_IF => {
            ifstat(ls, state, line)?;
        }
        TK_WHILE => {
            whilestat(ls, state, line)?;
        }
        TK_DO => {
            lex_next(ls, state)?; // skip DO
            block(ls, state)?;
            check_match(ls, state, TK_END, TK_DO, line)?;
        }
        TK_FOR => {
            forstat(ls, state, line)?;
        }
        TK_REPEAT => {
            repeatstat(ls, state, line)?;
        }
        TK_FUNCTION => {
            funcstat(ls, state, line)?;
        }
        TK_LOCAL => {
            lex_next(ls, state)?; // skip LOCAL
            if test_next(ls, state, TK_FUNCTION)? {
                localfunc(ls, state)?;
            } else {
                localstat(ls, state)?;
            }
        }
        TK_DBCOLON => {
            lex_next(ls, state)?; // skip '::'
            let name = str_check_name(ls, state)?;
            labelstat(ls, state, name, line)?;
        }

    Tbc,
    // C: OP_JMP,/*   sJ  pc += sJ  */
    Jmp,

    // C: OP_EQ,/* A B k  if ((R[A] == R[B]) ~= k) then pc++  */
    Eq,
    // C: OP_LT,/* A B k  if ((R[A] <  R[B]) ~= k) then pc++  */
    Lt,
    // C: OP_LE,/* A B k  if ((R[A] <= R[B]) ~= k) then pc++  */
    Le,

    // C: OP_EQK,/* A B k   if ((R[A] == K[B]) ~= k) then pc++  */
    EqK,
    // C: OP_EQI,/* A sB k  if ((R[A] == sB) ~= k) then pc++  */
    EqI,
    // C: OP_LTI,/* A sB k  if ((R[A] < sB) ~= k) then pc++  */
    LtI,
    // C: OP_LEI,/* A sB k  if ((R[A] <= sB) ~= k) then pc++  */
    LeI,
    // C: OP_GTI,/* A sB k  if ((R[A] > sB) ~= k) then pc++  */
    GtI,
    // C: OP_GEI,/* A sB k  if ((R[A] >= sB) ~= k) then pc++  */
    GeI,

    // C: OP_TEST,/*    A k    if (not R[A] == k) then pc++  */
    Test,
    // C: OP_TESTSET,/* A B k  if (not R[B] == k) then pc++ else R[A] := R[B]  */
    TestSet,

    // C: OP_CALL,/*     A B C    R[A], ... ,R[A+C-2] := R[A](R[A+1], ... ,R[A+B-1])  */
    Call,
    // C: OP_TAILCALL,/* A B C k  return R[A](R[A+1], ... ,R[A+B-1])  */
    TailCall,

    // C: OP_RETURN,/*  A B C k  return R[A], ... ,R[A+B-2]  */
    Return,
    // C: OP_RETURN0,/*           return  */
    Return0,
    // C: OP_RETURN1,/* A         return R[A]  */
    Return1,

    // C: OP_FORLOOP,/* A Bx  update counters; if loop continues then pc-=Bx  */
    ForLoop,
    // C: OP_FORPREP,/* A Bx  check values and prepare; if not to run then pc+=Bx+1  */
    ForPrep,

    // C: OP_TFORPREP,/* A Bx  create upvalue for R[A+3]; pc+=Bx  */
    TForPrep,
    // C: OP_TFORCALL,/* A C   R[A+4], ... ,R[A+3+C] := R[A](R[A+1], R[A+2])  */
    TForCall,
    // C: OP_TFORLOOP,/* A Bx  if R[A+2] ~= nil then { R[A]=R[A+2]; pc -= Bx }  */
    TForLoop,

    // C: OP_SETLIST,/* A B C k  R[A][C+i] := R[A+i], 1 <= i <= B  */
    SetList,

    // C: OP_CLOSURE,/* A Bx  R[A] := closure(KPROTO[Bx])  */
    Closure,

    // C: OP_VARARG,/* A C  R[A], R[A+1], ..., R[A+C-2] = vararg  */
    VarArg,

    // C: OP_VARARGPREP,/* A  (adjust vararg parameters)  */
    VarArgPrep,

    // C: OP_EXTRAARG/* Ax  extra (larger) argument for previous opcode  */
    ExtraArg,
}

/// Total number of opcodes.
///
/// C: `#define NUM_OPCODES ((int)(OP_EXTRAARG) + 1)`
pub const NUM_OPCODES: usize = OpCode::ExtraArg as usize + 1;

impl OpCode {
    /// Convert a raw `u32` opcode field value to an `OpCode`.
    ///
    /// Returns `None` if `v >= NUM_OPCODES`.
    ///
    /// C: `GET_OPCODE(i)` — `cast(OpCode, ((i)>>POS_OP) & MASK1(SIZE_OP,0))`
    ///
    /// TODO(port): replace explicit match with a safe transmute or `num_enum`
