                            state.table_raw_set(&ra_v, rb_v, rc_v.clone())?;
                            state.gc_barrier_back(&ra_v, &rc_v);
                        } else {
                            state.set_ci_savedpc(ci, pc);
                            state.set_top(state.ci_top(ci));
                            finish_set(state, ra_v, rb_v, rc_v, false)?;
